#!/usr/bin/env node
// Embeds the platform FFmpeg and ffprobe binaries as gzip-compressed base64 into
// src/ffmpeg-bundle.js so @yao-pkg/pkg can bundle them via the src/**/*.js glob.
// pkg.assets globs are broken for node20 targets, so binary files must live
// inside a bundled .js file and be extracted at runtime by src/runtime/ffmpeg.js.
//
// This file is generated at build time and is NOT committed to the repo (gitignored).
// Each platform produces its own platform-specific ffmpeg-bundle.js.
//
// Run: node scripts/generate-ffmpeg-bundle.js

'use strict';

const fs     = require('fs');
const path   = require('path');
const zlib   = require('zlib');
const crypto = require('crypto');

const ROOT       = path.resolve(__dirname, '..');
const VENDOR_DIR = path.join(ROOT, 'vendor', 'ffmpeg');
const OUTPUT     = path.join(ROOT, 'src', 'ffmpeg-bundle.js');

const FFMPEG_BIN  = process.platform === 'win32' ? 'ffmpeg.exe'  : 'ffmpeg';
const FFPROBE_BIN = process.platform === 'win32' ? 'ffprobe.exe' : 'ffprobe';

function bundleBinary(name, binPath) {
  if (!fs.existsSync(binPath)) {
    console.error(`ERROR: ${name} not found at ${binPath}`);
    console.error('Run: node scripts/fetch-ffmpeg.js');
    process.exit(1);
  }

  const raw  = fs.readFileSync(binPath);
  const hash = crypto.createHash('sha256').update(raw).digest('hex');
  const compressed = zlib.gzipSync(raw, { level: 9 });
  const b64  = compressed.toString('base64');
  const sizeMb = (raw.length / 1024 / 1024).toFixed(1);
  const compMb = (compressed.length / 1024 / 1024).toFixed(1);

  console.log(`  ${name}: ${sizeMb} MB -> ${compMb} MB compressed`);
  return { b64, hash };
}

console.log(`\nGenerating FFmpeg bundle for ${process.platform}/${process.arch}...`);

const ffmpeg  = bundleBinary('ffmpeg',  path.join(VENDOR_DIR, FFMPEG_BIN));
const ffprobe = bundleBinary('ffprobe', path.join(VENDOR_DIR, FFPROBE_BIN));

const lines = [
  '// AUTO-GENERATED by scripts/generate-ffmpeg-bundle.js — do not edit by hand.',
  '// Platform FFmpeg/ffprobe binaries, gzip-compressed and embedded as base64.',
  '// NOT committed to the repo (gitignored). Regenerated on each platform build.',
  '',
  '\'use strict\';',
  '',
  'module.exports = {',
  `  platform: ${JSON.stringify(process.platform)},`,
  `  arch:     ${JSON.stringify(process.arch)},`,
  `  ffmpeg: {`,
  `    data:       Buffer.from(${JSON.stringify(ffmpeg.b64)}, 'base64'),`,
  `    sha256:     ${JSON.stringify(ffmpeg.hash)},`,
  `    compressed: true,`,
  `  },`,
  `  ffprobe: {`,
  `    data:       Buffer.from(${JSON.stringify(ffprobe.b64)}, 'base64'),`,
  `    sha256:     ${JSON.stringify(ffprobe.hash)},`,
  `    compressed: true,`,
  `  },`,
  '};',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, lines, 'utf8');
console.log(`Generated ${OUTPUT}`);
